$data | Convert-EAIEvent -PropertyMap @{
    event_ci = 'HostName'
    event_name = 'AlertTitle'
    event_description = 'Details'
    event_object = 'Component'
    event_severity = 'Severity'
    event_source = { 'VendorX' }
}

# Create a device with custom properties (note the array format)
$data = @{
    name = "server1"
    displayName = "Production Server"
    preferredCollectorId = 5
    customProperties = @(
        @{ name = "environment"; value = "production" }
        @{ name = "owner"; value = "ops-team" }
    )
}
Invoke-LMAPIRequest -ResourcePath "/device/devices" -Method POST -Data $data

# Update a resource with PATCH
$updates = @{
    description = "Updated description"
}
Invoke-LMAPIRequest -ResourcePath "/device/devices/123" -Method PATCH -Data $updates

# Get paginated results manually
$offset = 0
$size = 1000
$allResults = @()
do {
    $response = Invoke-LMAPIRequest -ResourcePath "/device/devices" -Method GET -QueryParams @{ size = $size; offset = $offset }
    $allResults += $response.items
    $offset += $size
} while ($allResults.Count -lt $response.total)

New-LMActionChain -Name "Disk Chain" -Stages @(
    @{ id = 123; type = 'diagnosticSource' },
    @{ id = 456; type = 'remediationSource' }
)

$config = @{
    name = "Disk Chain"
    stages = @(
        @{ id = 123; type = 'diagnosticSource' }
    )
}
New-LMActionChain -InputObject $config

#Create a new datasource
$config = @{
    name = "MyDatasource"
    # Additional configuration properties
}
New-LMDatasource -Datasource $config

$config = @{
    name = "Critical Chain"
    destinations = @(
        @{
            type = "timebased"
            stages = @(
                @(@{ type = "user"; addr = "admin@example.com"; method = "email" })
            )
        }
    )
}
New-LMEscalationChain -InputObject $config

$config = @{
    name = "Production Logs"
    query = "environment:production"
}
New-LMLogAlertGroup -InputObject $config

$config = @{
    name = "MyLogicModule"
    # Additional configuration properties
}
New-LMLogicModule -LogicModule $config -Type "datasources"

