$event = @{
    cef = @{
        event_ci = 'server01'
        event_object = 'CPU'
        event_source = 'Meraki'
        event_name = 'High CPU'
        event_description = 'CPU above threshold'
        event_severity = 4
        event_time = (Format-EAIEventTime -DateTime (Get-Date))
        event_id = [guid]::NewGuid().ToString()
        event_domain = ''
        source_record = @{ device = 'server01' }
        class = 'event'
        version = '1.1'
    }
    enrichments = @{}
}
Send-EAIEvents -Events $event

# Replace with a single skip override
Set-EAISdtOverride -ScheduleId $id -Override @(
    @{
        originalInstanceId = @{
            scheduleId = $id
            startTime  = '2026-07-21T16:00:00.000Z'
        }
        status  = 'SKIPPED'
        summary = 'bulk skip'
    }
)
